import { cn } from '@/utils/cn';
import { getColor } from '@/utils/helper';
import {
  Component,
  createEffect,
  createMemo,
  createSignal,
  For,
  mergeProps,
  on,
  Show,
  type ParentComponent,
} from 'solid-js';
import type { SliderProps, SliderTooltipProps } from './slider.types';

type SliderTooltipInternalProps = SliderTooltipProps & {
  content: string;
  open: boolean;
};

const SliderTooltip: ParentComponent<SliderTooltipInternalProps> = p => (
  <div
    class={cn(
      'tooltip',
      p.position === 'bottom' && 'tooltip-bottom',
      p.position === 'left' && 'tooltip-left',
      p.position === 'right' && 'tooltip-right',
      p.color && `tooltip-${p.color}`,
      p.open && 'tooltip-open',
      p.class,
    )}
    data-tip={p.content}
  >
    {p.children}
  </div>
);

const DEFAULT_PROPS: Partial<SliderProps> = {
  color: 'primary',
  min: 0,
  max: 100,
  step: 1,
  disabled: false,
  reverse: false,
  orientation: 'horizontal',
  dots: false,
  included: true,
  tooltip: {
    hidden: false,
  },
};

export const Slider: Component<SliderProps> = p => {
  p = mergeProps(DEFAULT_PROPS, p);

  // Internal state
  const [activeThumb, setActiveThumb] = createSignal<0 | 1 | null>(null);
  const [hoveredThumb, setHoveredThumb] = createSignal<0 | 1 | null>(null);

  // Refs
  let railRef: HTMLDivElement | undefined;

  // Determine if range mode
  const isRange = createMemo(() => p.range === true);

  // Internal value state (for uncontrolled mode)
  const getInitialValue = (): number | [number, number] => {
    if (p.value !== undefined) return p.value;
    if (p.defaultValue !== undefined) return p.defaultValue;
    return isRange() ? ([p.min!, p.max!] as [number, number]) : p.min!;
  };

  const [internalValue, setInternalValue] = createSignal<number | [number, number]>(
    getInitialValue(),
  );

  // Sync with controlled value
  createEffect(
    on(
      () => p.value,
      newValue => {
        if (newValue !== undefined) {
          setInternalValue(newValue);
        }
      },
    ),
  );

  // Current value getter
  const currentValue = createMemo(() => {
    return p.value !== undefined ? p.value : internalValue();
  });

  // Get values as array for easy handling
  const valuesArray = createMemo<[number, number]>(() => {
    const val = currentValue();
    if (Array.isArray(val)) {
      return val as [number, number];
    }
    return [p.min!, val] as [number, number];
  });

  // Calculate percentage from value
  const valueToPercent = (value: number): number => {
    const { min, max } = p;
    const percent = ((value - min!) / (max! - min!)) * 100;
    return p.reverse ? 100 - percent : percent;
  };

  // Calculate value from percentage
  const percentToValue = (percent: number): number => {
    const { min, max, step } = p;
    const actualPercent = p.reverse ? 100 - percent : percent;
    let value = min! + (actualPercent / 100) * (max! - min!);

    // Snap to step if defined
    if (step !== null && step !== undefined) {
      value = Math.round(value / step) * step;
    }

    // Snap to marks if step is null
    if (step === null && p.marks) {
      const markValues = Object.keys(p.marks).map(Number);
      markValues.push(min!, max!);
      value = markValues.reduce((prev, curr) =>
        Math.abs(curr - value) < Math.abs(prev - value) ? curr : prev,
      );
    }

    return Math.max(min!, Math.min(max!, value));
  };

  // Get position from mouse/touch event
  const getPositionFromEvent = (event: MouseEvent | TouchEvent): number => {
    if (!railRef) return 0;

    const rect = railRef.getBoundingClientRect();
    const isVertical = p.orientation === 'vertical';

    let clientPos: number;
    if ('touches' in event) {
      clientPos = isVertical ? event.touches[0].clientY : event.touches[0].clientX;
    } else {
      clientPos = isVertical ? event.clientY : event.clientX;
    }

    let percent: number;
    if (isVertical) {
      percent = ((rect.bottom - clientPos) / rect.height) * 100;
    } else {
      percent = ((clientPos - rect.left) / rect.width) * 100;
    }

    return Math.max(0, Math.min(100, percent));
  };

  // Update value
  const updateValue = (newValue: number, thumbIndex: 0 | 1) => {
    let finalValue: number | [number, number];

    if (isRange()) {
      const current = valuesArray();
      const newValues: [number, number] = [...current];
      newValues[thumbIndex] = newValue;

      // Ensure min <= max for range
      if (thumbIndex === 0 && newValue > newValues[1]) {
        newValues[0] = newValues[1];
      } else if (thumbIndex === 1 && newValue < newValues[0]) {
        newValues[1] = newValues[0];
      }

      finalValue = newValues;
    } else {
      finalValue = newValue;
    }

    // Update internal state (for uncontrolled mode)
    if (p.value === undefined) {
      setInternalValue(finalValue);
    }

    // Call onChange callback
    p.onChange?.(finalValue);
  };

  // Handle mouse/touch start on thumb
  const handleThumbMouseDown = (event: MouseEvent | TouchEvent, thumbIndex: 0 | 1) => {
    if (p.disabled) return;
    event.preventDefault();
    event.stopPropagation();

    setActiveThumb(thumbIndex);

    const handleMove = (e: MouseEvent | TouchEvent) => {
      const percent = getPositionFromEvent(e);
      const value = percentToValue(percent);
      updateValue(value, thumbIndex);
    };

    const handleEnd = () => {
      setActiveThumb(null);
      document.removeEventListener('mousemove', handleMove);
      document.removeEventListener('mouseup', handleEnd);
      document.removeEventListener('touchmove', handleMove);
      document.removeEventListener('touchend', handleEnd);
    };

    document.addEventListener('mousemove', handleMove);
    document.addEventListener('mouseup', handleEnd);
    document.addEventListener('touchmove', handleMove);
    document.addEventListener('touchend', handleEnd);
  };

  // Handle click on rail
  const handleRailClick = (event: MouseEvent) => {
    if (p.disabled) return;

    const percent = getPositionFromEvent(event);
    const clickedValue = percentToValue(percent);

    if (isRange()) {
      // Find closest thumb
      const [v0, v1] = valuesArray();
      const dist0 = Math.abs(clickedValue - v0);
      const dist1 = Math.abs(clickedValue - v1);
      const closestThumb: 0 | 1 = dist0 <= dist1 ? 0 : 1;
      updateValue(clickedValue, closestThumb);
    } else {
      updateValue(clickedValue, 1);
    }
  };

  // Calculate marks
  const marksList = createMemo(() => {
    if (!p.marks) return [];
    return Object.entries(p.marks).map(([key, value]) => {
      const numKey = Number(key);
      const percent = valueToPercent(numKey);
      const markData = typeof value === 'string' ? { label: value, style: undefined } : value;
      return {
        value: numKey,
        percent,
        ...markData,
      };
    });
  });

  // Calculate dots
  const dotsList = createMemo(() => {
    if (!p.dots) return [];
    const { min, max, step } = p;
    if (!step || step <= 0) return [];

    const dots: { value: number; percent: number }[] = [];
    for (let v = min!; v <= max!; v += step) {
      dots.push({
        value: v,
        percent: valueToPercent(v),
      });
    }
    return dots;
  });

  // Check if value is in range (for included styling)
  const isInRange = (value: number): boolean => {
    if (!p.included) return false;
    const [v0, v1] = valuesArray();
    if (isRange()) {
      return value >= v0 && value <= v1;
    }
    return value >= p.min! && value <= v1;
  };

  // Track styles
  const trackStyle = createMemo(() => {
    const [v0, v1] = valuesArray();
    const isVertical = p.orientation === 'vertical';

    let start: number, length: number;

    if (isRange()) {
      const p0 = valueToPercent(v0);
      const p1 = valueToPercent(v1);
      start = Math.min(p0, p1);
      length = Math.abs(p1 - p0);
    } else {
      if (p.reverse) {
        const p1 = valueToPercent(v1);
        start = p1;
        length = 100 - p1;
      } else {
        start = 0;
        length = valueToPercent(v1);
      }
    }

    if (isVertical) {
      return { bottom: `${start}%`, height: `${length}%` };
    }
    return { left: `${start}%`, width: `${length}%` };
  });

  // Thumb positions
  const thumbPositions = createMemo(() => {
    const [v0, v1] = valuesArray();
    const isVertical = p.orientation === 'vertical';

    const p0 = valueToPercent(v0);
    const p1 = valueToPercent(v1);

    if (isVertical) {
      return [{ bottom: `${p0}%` }, { bottom: `${p1}%` }];
    }
    return [{ left: `${p0}%` }, { left: `${p1}%` }];
  });

  // Tooltip formatter
  const formatTooltip = (value: number): string => {
    if (p.tooltip?.formatter === null) return '';
    if (typeof p.tooltip?.formatter === 'function') {
      return String(p.tooltip.formatter(value));
    }
    return String(value);
  };

  // Should show tooltip
  const shouldShowTooltip = (thumbIndex: 0 | 1): boolean => {
    if (p.tooltip?.forceOpen === false) return false;
    if (p.tooltip?.forceOpen === true) return true;
    return activeThumb() === thumbIndex || hoveredThumb() === thumbIndex;
  };

  // Get tooltip props excluding internal ones
  const getTooltipProps = () => {
    if (!p.tooltip) return {};
    const { forceOpen, formatter, hidden, ...rest } = p.tooltip;
    return rest;
  };

  const isVertical = () => p.orientation === 'vertical';

  return (
    <div
      class={cn(
        'sli01',
        getColor(p.color!),
        isVertical() && 'sli02',
        p.disabled && 'sli03',
        p.class?.root,
      )}
      data-disabled={p.disabled || undefined}
    >
      {/* Rail */}
      <div ref={railRef} class={cn('sli04', p.class?.rail)} onClick={handleRailClick}>
        {/* Track */}
        <Show when={p.included !== false}>
          <div class={cn('sli05', p.class?.track)} style={trackStyle()} />
        </Show>

        {/* Dots */}
        <For each={dotsList()}>
          {dot => (
            <div
              class={cn('sli09', isInRange(dot.value) && 'sli10', p.class?.dot)}
              style={isVertical() ? { bottom: `${dot.percent}%` } : { left: `${dot.percent}%` }}
            />
          )}
        </For>

        {/* Marks */}
        <For each={marksList()}>
          {mark => (
            <>
              <div
                class={cn('sli11', isInRange(mark.value) && 'sli12', p.class?.mark)}
                style={isVertical() ? { bottom: `${mark.percent}%` } : { left: `${mark.percent}%` }}
              />
              <span
                class={cn('sli13', isInRange(mark.value) && 'sli14', p.class?.markText)}
                style={{
                  ...(isVertical() ? { bottom: `${mark.percent}%` } : { left: `${mark.percent}%` }),
                  ...mark.style,
                }}
              >
                {mark.label}
              </span>
            </>
          )}
        </For>

        {/* Thumbs */}
        <Show when={isRange()}>
          <div class="sli06" style={thumbPositions()[0]}>
            <Show
              when={!p.tooltip?.hidden}
              fallback={
                <div
                  class={cn('sli07', activeThumb() === 0 && 'sli08', p.class?.handle)}
                  tabIndex={p.disabled ? -1 : 0}
                  role="slider"
                  aria-valuemin={p.min}
                  aria-valuemax={p.max}
                  aria-valuenow={valuesArray()[0]}
                  aria-disabled={p.disabled}
                  onMouseDown={e => handleThumbMouseDown(e, 0)}
                  onTouchStart={e => handleThumbMouseDown(e, 0)}
                  onMouseEnter={() => setHoveredThumb(0)}
                  onMouseLeave={() => setHoveredThumb(null)}
                  onFocus={() => setHoveredThumb(0)}
                  onBlur={() => setHoveredThumb(null)}
                />
              }
            >
              <SliderTooltip
                content={formatTooltip(valuesArray()[0])}
                open={shouldShowTooltip(0)}
                position={isVertical() ? 'right' : 'top'}
                {...getTooltipProps()}
              >
                <div
                  class={cn('sli07', activeThumb() === 0 && 'sli08', p.class?.handle)}
                  tabIndex={p.disabled ? -1 : 0}
                  role="slider"
                  aria-valuemin={p.min}
                  aria-valuemax={p.max}
                  aria-valuenow={valuesArray()[0]}
                  aria-disabled={p.disabled}
                  onMouseDown={e => handleThumbMouseDown(e, 0)}
                  onTouchStart={e => handleThumbMouseDown(e, 0)}
                  onMouseEnter={() => setHoveredThumb(0)}
                  onMouseLeave={() => setHoveredThumb(null)}
                  onFocus={() => setHoveredThumb(0)}
                  onBlur={() => setHoveredThumb(null)}
                />
              </SliderTooltip>
            </Show>
          </div>
        </Show>

        <div class="sli06" style={thumbPositions()[1]}>
          <Show
            when={!p.tooltip?.hidden}
            fallback={
              <div
                class={cn('sli07', activeThumb() === 1 && 'sli08', p.class?.handle)}
                tabIndex={p.disabled ? -1 : 0}
                role="slider"
                aria-valuemin={p.min}
                aria-valuemax={p.max}
                aria-valuenow={valuesArray()[1]}
                aria-disabled={p.disabled}
                onMouseDown={e => handleThumbMouseDown(e, 1)}
                onTouchStart={e => handleThumbMouseDown(e, 1)}
                onMouseEnter={() => setHoveredThumb(1)}
                onMouseLeave={() => setHoveredThumb(null)}
                onFocus={() => setHoveredThumb(1)}
                onBlur={() => setHoveredThumb(null)}
              />
            }
          >
            <SliderTooltip
              content={formatTooltip(valuesArray()[1])}
              open={shouldShowTooltip(1)}
              position={isVertical() ? 'right' : 'top'}
              {...getTooltipProps()}
            >
              <div
                class={cn('sli07', activeThumb() === 1 && 'sli08', p.class?.handle)}
                tabIndex={p.disabled ? -1 : 0}
                role="slider"
                aria-valuemin={p.min}
                aria-valuemax={p.max}
                aria-valuenow={valuesArray()[1]}
                aria-disabled={p.disabled}
                onMouseDown={e => handleThumbMouseDown(e, 1)}
                onTouchStart={e => handleThumbMouseDown(e, 1)}
                onMouseEnter={() => setHoveredThumb(1)}
                onMouseLeave={() => setHoveredThumb(null)}
                onFocus={() => setHoveredThumb(1)}
                onBlur={() => setHoveredThumb(null)}
              />
            </SliderTooltip>
          </Show>
        </div>
      </div>
    </div>
  );
};
